import json

def solve(events_json):
    events = json.loads(events_json)
    counts = {"c": 0, "u": 0, "d": 0}
    timestamps = []
    for e in events:
        op = e["payload"]["op"]
        if op in counts:
            counts[op] += 1
        timestamps.append(e["payload"]["ts_ms"])
    timestamps.sort()
    if len(timestamps) < 2:
        avg_interval = 0
    else:
        intervals = [timestamps[i+1] - timestamps[i] for i in range(len(timestamps)-1)]
        avg_interval = round(sum(intervals) / len(intervals), 1)
    return json.dumps({"counts": counts, "avg_interval_ms": avg_interval})
